def _piece_destinations(board: list[int], from_idx: int, piece: int, player: int) -> list[int]:
    r = from_idx // 5
    c = from_idx % 5

    if piece in (1, 4):
        offsets = [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)]
    elif piece in (2, 5):
        offsets = [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)]
    else:
        offsets = [(0, 3), (1, 2), (2, 1), (3, 0)]

    if player == 2:
        offsets = [(-dr, dc) for dr, dc in offsets]

    seen = set()
    dests = []
    for dr, dc in offsets:
        rr = r + dr
        cc = c + dc
        if 0 <= rr < 5 and 0 <= cc < 5:
            to_idx = rr * 5 + cc
            if to_idx not in seen and not _is_friendly(board[to_idx], player):
                seen.add(to_idx)
                dests.append(to_idx)

    return dests

