    player = state["current_player"]
    actions = []

    for from_index in range(25):
        piece = board[from_index]
        if not _is_friendly(piece, player):
            continue
        for to_index in _piece_moves(board, from_index, piece):
            target = board[to_index]
            if not _is_friendly(target, player):
                actions.append(from_index * 25 + to_index)

    return actions if actions else [625]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]
    new_player = 2 if player == 1 else 1

    if action == 625:
        new_board[25] += 1
        return {"board": new_board, "current_player": new_player}

    from_index = action // 25
    to_index = action % 25

    piece = new_board[from_index]
    new_board[from_index] = 0
    new_board[to_index] = piece
    new_board[25] += 1

    return {"board": new_board, "current_player": new_player}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    has_p1_general = False
    has_p2_general = False

    for i in range(25):
        v = board[i]
        if v == 1:
            has_p1_general = True
        elif v == 4:
            has_p2_general = True

    if not has_p1_general or not has_p2_general:
        return True

    if board[25] >= 100:
        return True

    return False


def returns(state: dict) -> dict:
    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    board = state["board"]
    has_p1_general = False
    has_p2_general = False

    for i in range(25):
        v = board[i]
        if v == 1:
            has_p1_general = True
        elif v == 4:
            has_p2_general = True

    if has_p1_general and not has_p2_general:
        return {1: 1.0, 2: -1.0}
    if has_p2_general and not has_p1_general:
        return {1: -1.0, 2: 1.0}
    return {1: 0.0, 2: 0.0}


def _is_friendly(piece: int, player: int) -> bool:
    if player == 1:
        return piece in (1, 2, 3)
    return piece in (4, 5, 6)


def _piece_moves(board: list[int], from_index: int, piece: int) -> list[int]:
    r = from_index // 5
    c = from_index % 5

    if piece in (1, 4):
        offsets = [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)]
    elif piece in (2, 5):
        if piece == 2:
            offsets = [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)]
        else:
            offsets = [(-1, 0), (-2, 0), (-1, -1), (-1, 1), (1, 0)]
    else:
        offsets = [(0, 3), (1, 2), (2, 1), (3, 0), (0, -3), (-1, -2), (-2, -1), (-3, 0)]

    moves = []
    for dr, dc in offsets:
        rr = r + dr
        cc = c + dc
        if 0 <= rr < 5 and 0 <= cc < 5:
            moves.append(rr * 5 + cc)
    return moves
